triggered := false
if ((#MotionSensor #Entrance).motionSensor_motion == true) {
if (triggered == false) {
(#Light #Entrance).light_moveToBrightness(100, 0)
        delay(3 SEC)
(#Light #Switch #Entrance).switch_off()
        triggered = true
}
}
else {
triggered = false
}

